INSERT INTO blog_posts (title, excerpt, content, category, author, author_image, image_url, thumbnail, date, read_time, views, likes, comments, featured, published, slug, created_at, updated_at) VALUES
('Understanding Heart Disease: Prevention and Management', 'Learn about the latest advances in heart disease prevention, diagnosis, and treatment options.', 'Heart disease remains the leading cause of death worldwide. This comprehensive guide covers everything from risk factors to cutting-edge treatments including lifestyle modifications, medication management, and surgical interventions.', 'Cardiology', 'Dr. Emily Carter', 'https://randomuser.me/api/portraits/women/1.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 1 DAY, '8 min read', 2345, 189, 45, true, true, 'understanding-heart-disease', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('5 Signs You Should See a Cardiologist', 'Do not ignore these warning signs that could indicate serious heart problems.', 'Early detection of heart conditions can save lives. Here are 5 critical signs that require immediate attention from a cardiologist: chest pain, shortness of breath, palpitations, dizziness, and swelling in the legs.', 'Cardiology', 'Dr. Emily Carter', 'https://randomuser.me/api/portraits/women/1.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 3 DAY, '6 min read', 1876, 156, 34, false, true, 'signs-see-cardiologist', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Heart Surgery: What to Expect', 'A comprehensive guide to preparing for and recovering from heart surgery.', 'Heart surgery can be daunting. This guide walks you through every step of the journey from pre-operative preparation to post-surgical recovery and long-term care.', 'Cardiology', 'Dr. James Wilson', 'https://randomuser.me/api/portraits/men/2.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 2 DAY, '10 min read', 1567, 134, 28, true, true, 'heart-surgery-guide', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Managing High Blood Pressure Naturally', 'Discover effective natural ways to control and manage high blood pressure.', 'High blood pressure affects millions worldwide. Learn about dietary changes, exercise routines, and lifestyle modifications that can help you maintain healthy blood pressure levels without relying solely on medication.', 'Cardiology', 'Dr. James Wilson', 'https://randomuser.me/api/portraits/men/2.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 4 DAY, '7 min read', 1234, 98, 22, false, true, 'managing-high-blood-pressure', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Understanding Cholesterol: Good vs Bad', 'Learn the difference between good and bad cholesterol and how to maintain healthy levels.', 'Cholesterol management is crucial for heart health. This article explains the science behind HDL and LDL cholesterol and provides practical tips for maintaining optimal levels through diet and lifestyle changes.', 'Cardiology', 'Dr. Emily Carter', 'https://randomuser.me/api/portraits/women/1.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 5 DAY, '6 min read', 987, 76, 15, false, true, 'understanding-cholesterol', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Heart Attack Prevention: A Complete Guide', 'Everything you need to know about preventing heart attacks.', 'Heart attacks are often preventable with the right knowledge and lifestyle choices. This comprehensive guide covers risk factors, warning signs, and prevention strategies.', 'Cardiology', 'Dr. James Wilson', 'https://randomuser.me/api/portraits/men/2.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 6 DAY, '9 min read', 2156, 178, 42, true, true, 'heart-attack-prevention', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Living with Heart Failure: Tips and Support', 'Practical advice for managing life with heart failure.', 'A heart failure diagnosis can be overwhelming. This article provides practical tips for managing symptoms, maintaining quality of life, and finding support.', 'Cardiology', 'Dr. Emily Carter', 'https://randomuser.me/api/portraits/women/1.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 7 DAY, '8 min read', 876, 67, 12, false, true, 'living-with-heart-failure', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('The Future of Cardiology: AI and Heart Health', 'How artificial intelligence is revolutionizing cardiology.', 'AI is transforming healthcare, and cardiology is at the forefront. Learn about AI-powered diagnostics, personalized treatment plans, and the future of heart care.', 'Cardiology', 'Dr. James Wilson', 'https://randomuser.me/api/portraits/men/2.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 8 DAY, '7 min read', 1456, 112, 34, false, true, 'future-of-cardiology', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('The Ultimate Guide to Heart-Healthy Nutrition', 'Discover the best foods for heart health and learn how to create a sustainable diet plan.', 'What you eat directly impacts your heart health. This comprehensive guide covers the best and worst foods for your heart, including Mediterranean diet principles and practical meal planning strategies.', 'Nutrition & Dietetics', 'Dr. Raj Patel', 'https://randomuser.me/api/portraits/men/3.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 3 DAY, '7 min read', 1245, 98, 22, false, true, 'heart-healthy-nutrition', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Plant-Based Diet: Benefits and Meal Plans', 'Explore the health benefits of a plant-based diet with practical meal planning tips.', 'More people are adopting plant-based diets for health and environmental reasons. This guide covers the scientific evidence for plant-based nutrition and a 7-day meal plan.', 'Nutrition & Dietetics', 'Dr. Raj Patel', 'https://randomuser.me/api/portraits/men/3.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 5 DAY, '6 min read', 987, 76, 18, false, true, 'plant-based-diet', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Managing Diabetes Through Diet', 'Learn how proper nutrition can help manage and even prevent type 2 diabetes.', 'Diet plays a crucial role in diabetes management. This guide provides practical tips for blood sugar control including carbohydrate counting and meal timing strategies.', 'Nutrition & Dietetics', 'Dr. Sarah Johnson', 'https://randomuser.me/api/portraits/women/4.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 4 DAY, '8 min read', 876, 67, 15, false, true, 'diabetes-diet', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Superfoods for Brain Health', 'Discover the foods that boost brain function and protect against cognitive decline.', 'The brain requires specific nutrients to function optimally. Learn about the superfoods that can improve memory, focus, and long-term brain health.', 'Nutrition & Dietetics', 'Dr. Sarah Johnson', 'https://randomuser.me/api/portraits/women/4.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 6 DAY, '7 min read', 1654, 143, 29, false, true, 'superfoods-brain-health', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Intermittent Fasting: A Complete Guide', 'Everything you need to know about intermittent fasting and its health benefits.', 'Intermittent fasting has gained popularity for its potential health benefits. This guide explains different fasting methods, what to eat, and how to get started safely.', 'Nutrition & Dietetics', 'Dr. Raj Patel', 'https://randomuser.me/api/portraits/men/3.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 7 DAY, '9 min read', 2345, 198, 56, true, true, 'intermittent-fasting-guide', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Gut Health and Overall Wellness', 'Learn how gut health affects your entire body and how to improve it.', 'The gut microbiome plays a crucial role in overall health. This article explores the connection between gut health and immunity, mental health, and chronic disease prevention.', 'Nutrition & Dietetics', 'Dr. Sarah Johnson', 'https://randomuser.me/api/portraits/women/4.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 8 DAY, '8 min read', 1876, 156, 38, true, true, 'gut-health-wellness', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Vitamin D: The Sunshine Vitamin', 'Why vitamin D is essential for your health and how to maintain optimal levels.', 'Vitamin D deficiency is common worldwide. Learn about the importance of this essential vitamin, how to get enough, and the health benefits of maintaining optimal levels.', 'Nutrition & Dietetics', 'Dr. Raj Patel', 'https://randomuser.me/api/portraits/men/3.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 9 DAY, '6 min read', 987, 87, 19, false, true, 'vitamin-d-guide', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Healthy Eating on a Budget', 'Practical tips for eating healthy without breaking the bank.', 'Eating healthy does not have to be expensive. This guide provides practical tips for meal planning, smart shopping, and preparing nutritious meals on a budget.', 'Nutrition & Dietetics', 'Dr. Sarah Johnson', 'https://randomuser.me/api/portraits/women/4.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 10 DAY, '5 min read', 765, 54, 12, false, true, 'healthy-eating-budget', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Rehab After Knee Surgery: A Complete Guide', 'Step-by-step rehabilitation plan for a successful recovery after knee surgery.', 'Knee surgery recovery requires dedication and the right approach. This guide covers everything from day 1 post-surgery to full recovery including exercises and pain management strategies.', 'Physical Therapy', 'Dr. Maya Lee', 'https://randomuser.me/api/portraits/women/5.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 5 DAY, '9 min read', 2345, 189, 45, true, true, 'knee-surgery-rehab', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
