('Digital Detox: Reclaiming Your Life', 'The importance of disconnecting from technology for mental health.', 'Digital overload is affecting mental health. This article explores the benefits of a digital detox and provides strategies for reducing screen time.', 'Lifestyle & Wellness', 'Dr. Rebecca White', 'https://randomuser.me/api/portraits/women/21.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 12 DAY, '6 min read', 987, 76, 18, false, true, 'digital-detox', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Hydration: The Essential Guide', 'Why hydration is crucial for health and how to stay hydrated.', 'Proper hydration is essential for health. This guide explains why water matters and provides practical tips for staying hydrated.', 'Lifestyle & Wellness', 'Dr. Raj Patel', 'https://randomuser.me/api/portraits/men/3.jpg', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=800&h=400&fit=crop', 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&h=250&fit=crop', CURRENT_TIMESTAMP - INTERVAL 13 DAY, '5 min read', 876, 67, 15, false, true, 'hydration-guide', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO drugs (name, category, description, dosage, side_effects, rating, price, availability, manufacturer, drug_class, pregnancy_category, storage_conditions, half_life, onset_of_action, duration_of_action, metabolism, excretion, review_count, interactions, warnings, image_url, is_active, created_at, updated_at) VALUES
('Acetaminophen', 'Pain Relief', 'Acetaminophen is a widely used analgesic and antipyretic medication. It works by inhibiting prostaglandin synthesis in the central nervous system. Maximum daily dose should not exceed 4000mg to prevent hepatotoxicity.', '325-650mg every 4-6 hours, max 4000mg daily', 'Nausea, vomiting, headache, hepatotoxicity with overdose', 4.8, '$', 'Over-the-counter', 'Johnson & Johnson', 'Analgesic, Antipyretic', 'C', 'Room temperature 20-25°C', '2-3 hours', '30-60 min', '4-6 hours', 'Hepatic', 'Renal', 12456, '["Alcohol","Warfarin","Carbamazepine","Phenytoin"]', '["Max 4000mg daily","Liver damage risk with alcohol","Use caution in liver disease"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Ibuprofen', 'Pain Relief', 'Ibuprofen is a nonsteroidal anti-inflammatory drug (NSAID) that inhibits COX enzymes, reducing prostaglandin production. Used for headache, dental pain, menstrual cramps, and arthritis.', '200-400mg every 6-8 hours, max 1200mg OTC', 'GI upset, nausea, bleeding risk, cardiovascular risk', 4.7, '$', 'Over-the-counter', 'Pfizer', 'NSAID', 'D', 'Room temperature 20-25°C', '2-4 hours', '30-60 min', '4-6 hours', 'Hepatic', 'Renal', 9876, '["Aspirin","Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["GI bleeding risk","Cardiovascular risk","Avoid in 3rd trimester"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Naproxen', 'Pain Relief', 'Naproxen is an NSAID with potent anti-inflammatory properties. Indicated for rheumatoid arthritis, osteoarthritis, gout, and pain management. Has a longer half-life allowing twice-daily dosing.', '220-550mg every 12 hours, max 1000mg daily', 'GI upset, headache, dizziness, GI bleeding, cardiovascular events', 4.6, '$', 'Over-the-counter', 'Bayer', 'NSAID', 'D', 'Room temperature 15-30°C', '12-17 hours', '30-60 min', '8-12 hours', 'Hepatic', 'Renal', 7654, '["Aspirin","Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["GI bleeding risk","Cardiovascular risk","Avoid in 3rd trimester"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Celecoxib', 'Pain Relief', 'Celecoxib is a selective COX-2 inhibitor NSAID that reduces inflammation and pain while sparing COX-1, resulting in fewer GI side effects.', '100-200mg twice daily, max 400mg daily', 'Dyspepsia, diarrhea, cardiovascular events, GI bleeding', 4.5, '$$$', 'Prescription only', 'Pfizer', 'COX-2 Inhibitor', 'D', 'Room temperature 20-25°C', '11-12 hours', '1-3 hours', '24 hours', 'Hepatic', 'Renal', 5432, '["Warfarin","Fluconazole","Lithium","ACE inhibitors"]', '["Cardiovascular risk","Avoid in sulfonamide allergy"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Diclofenac', 'Pain Relief', 'Diclofenac is an NSAID used for rheumatoid arthritis, osteoarthritis, ankylosing spondylitis, and acute gout. Available in tablets, injections, patches, and topical gel.', '50mg 2-3 times daily, max 150mg daily', 'GI upset, nausea, dizziness, GI bleeding, cardiovascular events', 4.6, '$$', 'Prescription only', 'Novartis', 'NSAID', 'D', 'Room temperature 20-25°C', '1-2 hours', '30-60 min', '6-8 hours', 'Hepatic', 'Renal', 4321, '["Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["Cardiovascular risk","Monitor LFTs","Avoid in 3rd trimester"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Tramadol', 'Pain Relief', 'Tramadol is a centrally acting analgesic with dual mechanism: μ-opioid receptor binding and serotonin/norepinephrine reuptake inhibition. Used for moderate to moderately severe pain.', '50-100mg every 4-6 hours, max 400mg daily', 'Nausea, dizziness, constipation, seizures, serotonin syndrome', 4.3, '$$$', 'Prescription only', 'Janssen', 'Opioid Analgesic', 'C', 'Room temperature 15-30°C', '6-7 hours', '1-2 hours', '4-6 hours', 'Hepatic', 'Renal', 8765, '["SSRIs","SNRIs","MAOIs","Benzodiazepines","Alcohol"]', '["Seizure risk","Serotonin syndrome","Dependence potential"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Morphine', 'Pain Relief', 'Morphine is a potent opioid analgesic acting on μ-opioid receptors. It is the standard for severe pain associated with cancer, MI, and severe trauma. Schedule II controlled substance.', '10-30mg every 4 hours, extended release 15-30mg every 8-12 hours', 'Constipation, nausea, sedation, respiratory depression, dependence', 4.8, '$$$$', 'Prescription only', 'Purdue Pharma', 'Opioid Analgesic', 'C', 'Room temperature 20-25°C', '2-4 hours', '15-30 min', '3-6 hours', 'Hepatic', 'Renal', 6543, '["Benzodiazepines","Barbiturates","Alcohol","MAOIs"]', '["Respiratory depression","Dependence potential","Withdrawal syndrome"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Oxycodone', 'Pain Relief', 'Oxycodone is a semisynthetic opioid analgesic derived from thebaine. Used for moderate to severe pain. Available as immediate-release and controlled-release formulations. Schedule II.', '5-10mg every 4-6 hours, controlled release 10-40mg every 12 hours', 'Constipation, nausea, sedation, respiratory depression, dependence', 4.7, '$$$$', 'Prescription only', 'Purdue Pharma', 'Opioid Analgesic', 'C', 'Room temperature 20-25°C', '3-5 hours', '30-60 min', '4-6 hours', 'Hepatic', 'Renal', 5432, '["Benzodiazepines","Alcohol","MAOIs","Grapefruit juice"]', '["Respiratory depression","Dependence","Tolerance","Withdrawal"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Hydrocodone', 'Pain Relief', 'Hydrocodone is a semi-synthetic opioid analgesic combined with acetaminophen or ibuprofen. Used for moderate to moderately severe pain. Schedule II controlled substance.', '5-10mg every 4-6 hours, max 60mg daily', 'Constipation, nausea, drowsiness, respiratory depression, hepatotoxicity', 4.6, '$$$$', 'Prescription only', 'AbbVie', 'Opioid Analgesic', 'C', 'Room temperature 20-25°C', '4-6 hours', '15-30 min', '4-6 hours', 'Hepatic', 'Renal', 4321, '["Benzodiazepines","Barbiturates","Alcohol","MAOIs"]', '["Respiratory depression","Dependence","Hepatotoxicity risk"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Codeine', 'Pain Relief', 'Codeine is an opioid analgesic prodrug metabolized to morphine by CYP2D6. Used for mild to moderate pain and as an antitussive. Efficacy depends on CYP2D6 metabolism.', '15-60mg every 4-6 hours, max 360mg daily', 'Constipation, nausea, drowsiness, respiratory depression, dependence', 4.4, '$$$', 'Prescription only', 'Teva', 'Opioid Analgesic', 'C', 'Room temperature 20-25°C', '3-4 hours', '30-60 min', '4-6 hours', 'Hepatic', 'Renal', 3210, '["Benzodiazepines","Alcohol","MAOIs","CNS depressants"]', '["Respiratory depression","CYP2D6 variability","Avoid in children"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Aspirin', 'Pain Relief', 'Aspirin is an NSAID with anti-inflammatory, analgesic, and antipyretic properties. Also used as an antiplatelet agent for cardiovascular prevention. Inhibits COX-1 and COX-2.', '325-650mg every 4-6 hours, low dose 81mg daily for prevention', 'GI upset, bleeding risk, Reye syndrome in children, hypersensitivity', 4.5, '$', 'Over-the-counter', 'Bayer', 'NSAID, Antiplatelet', 'D', 'Room temperature 20-25°C', '15-20 min', '30-60 min', '4-6 hours', 'Hepatic', 'Renal', 8765, '["Warfarin","Heparin","SSRIs","Corticosteroids","Alcohol"]', '["Bleeding risk","Reye syndrome","Avoid in children with fever"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Meloxicam', 'Pain Relief', 'Meloxicam is a preferential COX-2 inhibitor NSAID used for osteoarthritis and rheumatoid arthritis. Has a lower risk of GI ulceration compared to non-selective NSAIDs.', '7.5-15mg once daily', 'GI upset, nausea, dizziness, cardiovascular risk, GI bleeding', 4.5, '$$$', 'Prescription only', 'Boehringer Ingelheim', 'NSAID', 'D', 'Room temperature 20-25°C', '20 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 2345, '["Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["Cardiovascular risk","GI bleeding","Monitor renal function"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Ketorolac', 'Pain Relief', 'Ketorolac is an NSAID used for short-term management of moderately severe acute pain. Use limited to 5 days due to GI and renal risks.', '10mg every 4-6 hours, max 40mg daily, IM/IV 30-60mg', 'GI upset, nausea, bleeding, renal impairment, dizziness', 4.4, '$$$', 'Prescription only', 'Roche', 'NSAID', 'D', 'Room temperature 20-25°C', '5-6 hours', '30-60 min', '4-6 hours', 'Hepatic', 'Renal', 1234, '["Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["Limited to 5 days","GI bleeding","Renal risk"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Piroxicam', 'Pain Relief', 'Piroxicam is an NSAID with a long half-life allowing once-daily dosing. Used for rheumatoid arthritis, osteoarthritis, and ankylosing spondylitis.', '20mg once daily', 'GI upset, nausea, dizziness, GI bleeding, cardiovascular risk', 4.3, '$$$', 'Prescription only', 'Pfizer', 'NSAID', 'D', 'Room temperature 20-25°C', '50 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 987, '["Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["GI bleeding","Cardiovascular risk","Monitor renal function"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Indomethacin', 'Pain Relief', 'Indomethacin is a potent NSAID used for moderate to severe rheumatoid arthritis, osteoarthritis, ankylosing spondylitis, gout, and acute shoulder pain.', '25-50mg 2-3 times daily, max 200mg daily', 'GI upset, headache, dizziness, confusion, GI bleeding, renal impairment', 4.2, '$$$', 'Prescription only', 'Merck', 'NSAID', 'D', 'Room temperature 20-25°C', '4-5 hours', '30-60 min', '4-6 hours', 'Hepatic', 'Renal', 876, '["Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["Significant GI and CNS side effects","Use lowest dose"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Etodolac', 'Pain Relief', 'Etodolac is an NSAID used for osteoarthritis, rheumatoid arthritis, and acute pain. Has a lower risk of GI ulceration compared to some other NSAIDs.', '200-400mg 2-3 times daily, max 1200mg daily', 'GI upset, nausea, dizziness, GI bleeding, cardiovascular risk', 4.3, '$$$', 'Prescription only', 'Abbott', 'NSAID', 'D', 'Room temperature 20-25°C', '7 hours', '1-2 hours', '6-8 hours', 'Hepatic', 'Renal', 765, '["Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["GI bleeding","Cardiovascular risk","Monitor renal function"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Nabumetone', 'Pain Relief', 'Nabumetone is an NSAID prodrug that is metabolized to the active compound. Used for osteoarthritis and rheumatoid arthritis. Has a lower risk of GI ulceration.', '1000-2000mg once daily', 'GI upset, nausea, dizziness, GI bleeding, cardiovascular risk', 4.2, '$$$', 'Prescription only', 'GlaxoSmithKline', 'NSAID', 'D', 'Room temperature 20-25°C', '24 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 654, '["Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["GI bleeding","Cardiovascular risk","Monitor renal function"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Sulindac', 'Pain Relief', 'Sulindac is an NSAID prodrug used for osteoarthritis, rheumatoid arthritis, ankylosing spondylitis, and acute gout. Has a lower incidence of renal toxicity.', '150-200mg twice daily', 'GI upset, nausea, dizziness, GI bleeding, cardiovascular risk', 4.2, '$$$', 'Prescription only', 'Merck', 'NSAID', 'D', 'Room temperature 20-25°C', '7-8 hours', '1-2 hours', '6-8 hours', 'Hepatic', 'Renal', 543, '["Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["GI bleeding","Cardiovascular risk","Monitor renal function"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Fentanyl', 'Pain Relief', 'Fentanyl is a potent synthetic opioid analgesic used for severe pain management. Available in transdermal patches, lozenges, and injectable forms. 100 times more potent than morphine.', '12-100mcg/hour patch, lozenge 200-1600mcg', 'Constipation, nausea, sedation, respiratory depression, dependence', 4.9, '$$$$$', 'Prescription only', 'Janssen', 'Opioid Analgesic', 'C', 'Room temperature 20-25°C', '7-17 hours', '30-60 min', '12-24 hours', 'Hepatic', 'Renal', 4321, '["Benzodiazepines","Alcohol","MAOIs","CNS depressants"]', '["Respiratory depression","Dependence","Fatal overdose risk"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Buprenorphine', 'Pain Relief', 'Buprenorphine is a partial μ-opioid receptor agonist used for pain management and opioid addiction treatment. Has a ceiling effect for respiratory depression.', '0.2-0.4mg SL every 6-8 hours, patch 5-20mcg/hour', 'Constipation, nausea, sedation, headache, withdrawal syndrome', 4.5, '$$$$', 'Prescription only', 'Indivior', 'Opioid Analgesic', 'C', 'Room temperature 20-25°C', '24-48 hours', '30-60 min', '24 hours', 'Hepatic', 'Biliary', 2345, '["Benzodiazepines","Alcohol","CNS depressants","MAOIs"]', '["Ceiling effect","Dependence","Withdrawal","Respiratory depression"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Tramadol ER', 'Pain Relief', 'Extended-release tramadol for chronic moderate to moderately severe pain requiring continuous treatment. Provides around-the-clock pain relief.', '100-300mg once daily', 'Nausea, dizziness, constipation, seizures, serotonin syndrome, dependence', 4.3, '$$$', 'Prescription only', 'Janssen', 'Opioid Analgesic', 'C', 'Room temperature 20-25°C', '6-7 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 2345, '["SSRIs","SNRIs","MAOIs","Benzodiazepines","Alcohol"]', '["Seizure risk","Serotonin syndrome","Dependence","Not for acute pain"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Tapentadol', 'Pain Relief', 'Tapentadol is a centrally acting analgesic with dual mechanism: μ-opioid receptor agonism and norepinephrine reuptake inhibition. Used for moderate to severe pain.', '50-100mg every 4-6 hours, ER 50-250mg twice daily', 'Nausea, dizziness, constipation, sedation, serotonin syndrome, dependence', 4.4, '$$$$', 'Prescription only', 'Johnson & Johnson', 'Opioid Analgesic', 'C', 'Room temperature 20-25°C', '4 hours', '1-2 hours', '4-6 hours', 'Hepatic', 'Renal', 3456, '["SSRIs","SNRIs","MAOIs","Benzodiazepines","Alcohol"]', '["Serotonin syndrome","Seizures","Dependence","Not for acute pain"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Flurbiprofen', 'Pain Relief', 'Flurbiprofen is an NSAID used for rheumatoid arthritis, osteoarthritis, and pain management. Has potent anti-inflammatory properties.', '50-100mg 2-3 times daily, max 300mg', 'GI upset, nausea, bleeding risk, cardiovascular risk, renal impairment', 4.3, '$$$', 'Prescription only', 'Pfizer', 'NSAID', 'D', 'Room temperature 20-25°C', '5-6 hours', '1-2 hours', '6-8 hours', 'Hepatic', 'Renal', 2345, '["Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["GI bleeding","Cardiovascular risk","Avoid in 3rd trimester"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Oxaprozin', 'Pain Relief', 'Oxaprozin is an NSAID used for osteoarthritis and rheumatoid arthritis. Has a long half-life allowing once-daily dosing.', '600-1200mg once daily', 'GI upset, nausea, dizziness, GI bleeding, cardiovascular risk', 4.2, '$$$', 'Prescription only', 'Pfizer', 'NSAID', 'D', 'Room temperature 20-25°C', '50 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 1234, '["Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["GI bleeding","Cardiovascular risk","Monitor renal function"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Mefenamic Acid', 'Pain Relief', 'Mefenamic acid is an NSAID used for mild to moderate pain, including dysmenorrhea. Has analgesic and anti-inflammatory properties.', '250-500mg every 6 hours, max 1500mg daily', 'GI upset, nausea, diarrhea, GI bleeding, renal impairment', 4.2, '$$', 'Prescription only', 'Pfizer', 'NSAID', 'D', 'Room temperature 20-25°C', '2-4 hours', '1-2 hours', '4-6 hours', 'Hepatic', 'Renal', 2345, '["Warfarin","Lithium","Methotrexate","ACE inhibitors"]', '["GI bleeding","Renal impairment","Avoid in children"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO drugs (name, category, description, dosage, side_effects, rating, price, availability, manufacturer, drug_class, pregnancy_category, storage_conditions, half_life, onset_of_action, duration_of_action, metabolism, excretion, review_count, interactions, warnings, image_url, is_active, created_at, updated_at) VALUES
('Amoxicillin', 'Antibiotics', 'Amoxicillin is a broad-spectrum penicillin antibiotic used to treat various bacterial infections including respiratory tract infections, urinary tract infections, skin infections, and otitis media. It inhibits bacterial cell wall synthesis.', '250-500mg every 8 hours, 875mg every 12 hours', 'Diarrhea, nausea, rash, allergic reactions, Clostridium difficile infection', 4.6, '$$', 'Prescription only', 'GlaxoSmithKline', 'Penicillin', 'B', 'Room temperature 20-25°C', '1-1.3 hours', '1-2 hours', '8-12 hours', 'Hepatic', 'Renal', 8765, '["Warfarin","Methotrexate","Allopurinol","Probenecid"]', '["Allergic reactions","Diarrhea","C. difficile risk"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Ciprofloxacin', 'Antibiotics', 'Ciprofloxacin is a fluoroquinolone antibiotic used for urinary tract infections, respiratory infections, skin infections, and bone infections. It inhibits bacterial DNA gyrase and topoisomerase IV.', '250-750mg twice daily', 'Nausea, diarrhea, tendonitis, photosensitivity, CNS effects', 4.4, '$$$', 'Prescription only', 'Bayer', 'Fluoroquinolone', 'C', 'Room temperature 20-25°C', '4 hours', '1-2 hours', '12 hours', 'Hepatic', 'Renal', 7654, '["Warfarin","Theophylline","Tizanidine","Magnesium","Calcium"]', '["Tendonitis","Photosensitivity","Avoid in children","CNS effects"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Azithromycin', 'Antibiotics', 'Azithromycin is a macrolide antibiotic used for respiratory infections, skin infections, and STDs. It has a long half-life allowing once-daily dosing and short treatment courses.', '500mg once daily for 3 days, 500mg day 1 then 250mg days 2-5', 'Nausea, diarrhea, abdominal pain, headache, QT prolongation', 4.6, '$$$', 'Prescription only', 'Pfizer', 'Macrolide', 'B', 'Room temperature 20-25°C', '68 hours', '1-2 hours', '3-5 days', 'Hepatic', 'Biliary', 6543, '["Warfarin","Digoxin","Statins","Cisapride","Pimozide"]', '["QT prolongation","Hepatotoxicity","Diarrhea"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Doxycycline', 'Antibiotics', 'Doxycycline is a tetracycline antibiotic used for respiratory infections, acne, malaria prevention, and Lyme disease. It inhibits bacterial protein synthesis.', '100mg twice daily first day then 100mg once daily', 'Nausea, diarrhea, photosensitivity, teeth discoloration (children)', 4.5, '$$$', 'Prescription only', 'Pfizer', 'Tetracycline', 'D', 'Room temperature 20-25°C', '12-22 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 5432, '["Warfarin","Antacids","Calcium","Iron","Magnesium"]', '["Photosensitivity","Teeth discoloration","Avoid in children","Pregnant"]', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
